pub fn smoke_parse(path: &str, bytes: &[u8]) {
    match ElfImage::parse(bytes) {
        Ok(image) => {
            let plan = match image.load_plan(bytes) {
                Ok(plan) => plan,
                Err(error) => {
                    println!("elf: {} load plan failed: {}", path, error.as_str());
                    return;
                }
            };
            println!(
                "elf: {} entry=0x{:x} phoff={} phnum={} machine={} load_span=[0x{:x},0x{:x})",
                path,
                image.entry,
                image.phoff,
                image.phnum,
                image.machine,
                plan.min_vaddr,
                plan.max_vaddr
            );
            for segment in plan.segments() {
                println!(
                    "elf: load[{}] off=0x{:x} vaddr=0x{:x} filesz=0x{:x} memsz=0x{:x} flags=0x{:x} map=[0x{:x},0x{:x})",
                    segment.phdr_index,
                    segment.offset,
                    segment.vaddr,
                    segment.filesz,
                    segment.memsz,
                    segment.flags,
                    segment.map_start,
                    segment.map_end
                );
            }
            println!("elf: {} load_segments={}", path, plan.count);
        }
        Err(Error::BadMagic) => println!("elf: {} is not an ELF image", path),
        Err(error) => println!("elf: {} parse failed: {}", path, error.as_str()),
    }
}

