    }
}

pub fn putchar(byte: u8) {
    unsafe {
        while read_reg(UART_LSR) & UART_LSR_THRE == 0 {}
        write_reg(UART_RHR_THR, byte);
    }
}

pub fn shutdown() -> ! {
    unsafe {
        let _ = sbi_call(0x5352_5354, 0, 0, 0, 0);
        let _ = sbi_call(0x08, 0, 0, 0, 0);
    }
    park()
}

pub fn park() -> ! {
    loop {
        unsafe {
            asm!("wfi", options(nomem, nostack));
        }
    }
}

pub fn monotonic_time_us() -> u64 {
    read_time_ticks().saturating_mul(1_000_000) / TIMEBASE_HZ
}

pub fn read_time_ticks() -> u64 {
    let ticks: u64;
    unsafe {
        asm!("rdtime {}", out(reg) ticks, options(nomem, nostack, preserves_flags));
    }
    ticks
}

pub fn set_timer_after_us(delta_us: u64) {
    let delta_ticks = delta_us.saturating_mul(TIMEBASE_HZ) / 1_000_000;
    set_timer_ticks(read_time_ticks().saturating_add(delta_ticks.max(1)));
}

pub fn set_timer_ticks(ticks: u64) {
    unsafe {
        let error = sbi_call(SBI_EXT_TIME, SBI_EXT_TIME_SET_TIMER, ticks as usize, 0, 0);
        if error != 0 {
            let _ = sbi_call(SBI_LEGACY_SET_TIMER, 0, ticks as usize, 0, 0);
        }
    }
}

