unsafe fn sbi_call(eid: usize, fid: usize, arg0: usize, arg1: usize, arg2: usize) -> usize {
    let mut ret = arg0;
    asm!(
        "ecall",
        inlateout("a0") ret,
        in("a1") arg1,
        in("a2") arg2,
        in("a6") fid,
        in("a7") eid,
        options(nostack)
    );
    ret
}

