fn normalize_absolute_path(path: &str) -> String {
    let mut components: heapless_path::PathComponents = heapless_path::PathComponents::new();
    for component in path.split('/') {
        match component {
            "" | "." => {}
            ".." => components.pop(),
            name => components.push(name),
        }
    }
    components.to_absolute_string()
}

